import{_ as l,o as i,c as a,ae as e}from"./chunks/framework.D7zHIyZF.js";const o="/images/lan.png",h=JSON.parse('{"title":"局域网访问","description":"","frontmatter":{},"headers":[],"relativePath":"local/LAN.md","filePath":"local/LAN.md"}'),t={name:"local/LAN.md"};function n(c,r,d,s,p,_){return i(),a("div",null,[...r[0]||(r[0]=[e('<h1 id="局域网访问" tabindex="-1">局域网访问 <a class="header-anchor" href="#局域网访问" aria-label="Permalink to &quot;局域网访问&quot;">​</a></h1><h2 id="_1-前提" tabindex="-1">1.前提 <a class="header-anchor" href="#_1-前提" aria-label="Permalink to &quot;1.前提&quot;">​</a></h2><ul><li>ZError已在局域网内的一台计算机上运行且软件已打开局域网访问选项。</li><li>要访问的设备与ZError运行的设备位于同一局域网内</li></ul><h2 id="_2-找到zerror运行的计算机的ip地址" tabindex="-1">2.找到ZError运行的计算机的IP地址 <a class="header-anchor" href="#_2-找到zerror运行的计算机的ip地址" aria-label="Permalink to &quot;2.找到ZError运行的计算机的IP地址&quot;">​</a></h2><ol><li><p>打开命令提示符（Windows）或终端（macOS/Linux）。</p></li><li><p>输入以下命令并按下回车键：</p><ul><li>Windows：<code>ipconfig</code></li><li>macOS/Linux：<code>ifconfig</code></li></ul></li><li><p>找到IPv4地址</p><ul><li>Windows：查找“IPv4地址”行，通常在“以太网适配器”或“无线局域网适配器”下。</li><li>macOS/Linux：查找“inet”行，通常在“en0”或“wlan0”下。</li></ul><div class="pic"><img src="'+o+'" alt="编辑"></div></li><li><p>记录IPv4地址</p><ul><li>记下找到的IPv4地址，例如“192.168.137.1”</li></ul></li></ol><h2 id="_3-访问zerror并使用配置" tabindex="-1">3.访问ZError并使用配置 <a class="header-anchor" href="#_3-访问zerror并使用配置" aria-label="Permalink to &quot;3.访问ZError并使用配置&quot;">​</a></h2><ul><li>在要访问的设备上打开浏览器。</li><li>在地址栏中输入ZError运行的计算机的IP地址，后跟端口号（默认端口为3000）。</li><li>例如：<code>http://192.168.137.1:3000</code></li><li>按下回车键，即可访问ZError。</li></ul><p>在题库配置中将URL设置为<code>http://192.168.137.1:3000/query</code></p>',8)])])}const m=l(t,[["render",n]]);export{h as __pageData,m as default};
